import React, { useEffect, useState, useCallback } from 'react';
import { Link } from 'react-router-dom';
import { supabase } from '../utils/supabaseClient';
import ProductCard from '../components/ProductCard/ProductCard';
import './HomePage.css';

const BANNERS = [
  { id: 1, img: 'https://rukminim2.flixcart.com/fk-p-flap/1600/270/image/bc264b14f26a3038.jpg', link: '/products/Electronics', alt: 'Big Billion Days' },
  { id: 2, img: 'https://rukminim2.flixcart.com/fk-p-flap/1600/270/image/c8649b07b2f7c759.jpg', link: '/products/Fashion', alt: 'Fashion Sale' },
  { id: 3, img: 'https://rukminim2.flixcart.com/fk-p-flap/1600/270/image/2f09cc2ac1855ae6.jpg', link: '/products/Grocery', alt: 'Grocery Deals' },
];

const CATEGORY_TILES = [
  { label: 'Phones', path: '/products/Electronics', img: 'https://rukminim2.flixcart.com/flap/64/64/image/22fddf3c7da4c4f4.png', color: '#e3f2fd' },
  { label: 'Electronics', path: '/products/Electronics', img: 'https://rukminim2.flixcart.com/flap/64/64/image/69c6589653afdb9a.png', color: '#fce4ec' },
  { label: "Men's Fashion", path: '/products/Men', img: 'https://rukminim2.flixcart.com/fk-p-flap/64/64/image/0d75b34f7d8fbcb3.png', color: '#e8f5e9' },
  { label: "Women's Fashion", path: '/products/Women', img: 'https://rukminim2.flixcart.com/fk-p-flap/64/64/image/dff3f7adcf3a90c6.png', color: '#fff3e0' },
  { label: 'Home & Furniture', path: '/products/Home', img: 'https://rukminim2.flixcart.com/fk-p-flap/64/64/image/ab7e2b022a4587dd.jpg', color: '#ede7f6' },
  { label: 'Appliances', path: '/products/TVs', img: 'https://rukminim2.flixcart.com/fk-p-flap/64/64/image/0139228b2f7eb413.jpg', color: '#e0f2f1' },
  { label: 'Books', path: '/products/Books', img: 'https://rukminim2.flixcart.com/fk-p-flap/64/64/image/71050627a56b4693.png', color: '#fff8e1' },
  { label: 'Sports', path: '/products/Sports', img: 'https://rukminim2.flixcart.com/fk-p-flap/64/64/image/dff3f7adcf3a90c6.png', color: '#e3f2fd' },
  { label: 'Grocery', path: '/products/Grocery', img: 'https://rukminim2.flixcart.com/flap/64/64/image/29327f40e9c4d26b.png', color: '#f1f8e9' },
  { label: 'Beauty', path: '/products/Beauty', img: 'https://rukminim2.flixcart.com/fk-p-flap/64/64/image/0d75b34f7d8fbcb3.png', color: '#fce4ec' },
];

const ProductSection = ({ title, subtitle, products, viewAllLink }) => (
  <div className="product-section">
    <div className="section-header">
      <div>
        <h2 className="section-title">{title}</h2>
        {subtitle && <p className="section-subtitle">{subtitle}</p>}
      </div>
      <Link to={viewAllLink} className="view-all-btn">VIEW ALL</Link>
    </div>
    <div className="products-grid-horizontal">
      {products.map(product => (
        <div key={product.id} className="product-grid-item">
          <ProductCard product={product} />
        </div>
      ))}
    </div>
  </div>
);

const HomePage = () => {
  const [currentBanner, setCurrentBanner] = useState(0);
  const [products, setProducts] = useState({
    electronics: [], fashion: [], topDeals: [], recommended: [], grocery: [], books: []
  });
  const [loading, setLoading] = useState(true);

  const fetchProducts = useCallback(async () => {
    setLoading(true);
    try {
      const [electronics, fashion, topDeals, recommended, grocery, books] = await Promise.all([
        supabase.from('products').select('*').eq('category', 'Electronics').limit(8),
        supabase.from('products').select('*').in('category', ['Men', 'Women']).limit(8),
        supabase.from('products').select('*').order('rating', { ascending: false }).limit(8),
        supabase.from('products').select('*').order('created_at', { ascending: false }).limit(8),
        supabase.from('products').select('*').eq('category', 'Grocery').limit(8),
        supabase.from('products').select('*').eq('category', 'Books').limit(8),
      ]);
      setProducts({
        electronics: electronics.data || [],
        fashion: fashion.data || [],
        topDeals: topDeals.data || [],
        recommended: recommended.data || [],
        grocery: grocery.data || [],
        books: books.data || [],
      });
    } finally { setLoading(false); }
  }, []);

  useEffect(() => { fetchProducts(); }, [fetchProducts]);

  // Banner auto-play
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentBanner(prev => (prev + 1) % BANNERS.length);
    }, 4000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="home-page">
      {/* Hero Banner Carousel */}
      <div className="banner-carousel">
        <div className="banner-slides" style={{ transform: `translateX(-${currentBanner * 100}%)` }}>
          {BANNERS.map(banner => (
            <Link key={banner.id} to={banner.link} className="banner-slide">
              <img
                src={banner.img}
                alt={banner.alt}
                onError={e => { e.target.src = `https://via.placeholder.com/1600x270/2874f0/ffffff?text=${banner.alt}`; }}
              />
            </Link>
          ))}
        </div>
        <div className="banner-dots">
          {BANNERS.map((_, i) => (
            <button
              key={i}
              className={`banner-dot ${i === currentBanner ? 'active' : ''}`}
              onClick={() => setCurrentBanner(i)}
            />
          ))}
        </div>
        <button className="banner-arrow banner-prev" onClick={() => setCurrentBanner(p => (p - 1 + BANNERS.length) % BANNERS.length)}>‹</button>
        <button className="banner-arrow banner-next" onClick={() => setCurrentBanner(p => (p + 1) % BANNERS.length)}>›</button>
      </div>

      <div className="home-content">
        {/* Category Tiles */}
        <div className="category-tiles-section">
          <div className="category-tiles">
            {CATEGORY_TILES.map(cat => (
              <Link key={cat.label} to={cat.path} className="category-tile">
                <div className="category-tile-img-wrap" style={{ background: cat.color }}>
                  <img
                    src={cat.img}
                    alt={cat.label}
                    onError={e => { e.target.style.display = 'none'; }}
                  />
                </div>
                <span className="category-tile-label">{cat.label}</span>
              </Link>
            ))}
          </div>
        </div>

        {/* Promotional Banners Row */}
        <div className="promo-banners">
          <Link to="/products/Electronics" className="promo-banner" style={{ background: 'linear-gradient(135deg, #2196f3, #673ab7)' }}>
            <div className="promo-text">
              <div className="promo-tag">Up to 80% off</div>
              <div className="promo-title">Electronics Sale</div>
              <div className="promo-subtitle">Smartphones, Laptops & More</div>
            </div>
            <div className="promo-icon">📱</div>
          </Link>
          <Link to="/products/Home" className="promo-banner" style={{ background: 'linear-gradient(135deg, #ff9800, #e91e63)' }}>
            <div className="promo-text">
              <div className="promo-tag">Starting ₹99</div>
              <div className="promo-title">Home Decor</div>
              <div className="promo-subtitle">Transform your space</div>
            </div>
            <div className="promo-icon">🏠</div>
          </Link>
          <Link to="/products/Women" className="promo-banner" style={{ background: 'linear-gradient(135deg, #e91e63, #ff5722)' }}>
            <div className="promo-text">
              <div className="promo-tag">New Arrivals</div>
              <div className="promo-title">Women's Fashion</div>
              <div className="promo-subtitle">Trendy styles just landed</div>
            </div>
            <div className="promo-icon">👗</div>
          </Link>
        </div>

        {/* Product Sections */}
        {loading ? (
          <div className="loading-sections">
            {[1,2,3].map(i => <div key={i} className="section-skeleton" />)}
          </div>
        ) : (
          <>
            {products.topDeals.length > 0 && (
              <ProductSection
                title="🔥 Top Deals"
                subtitle="Handpicked deals just for you"
                products={products.topDeals}
                viewAllLink="/products"
              />
            )}
            {products.electronics.length > 0 && (
              <ProductSection
                title="📱 Electronics"
                subtitle="Phones, Laptops, Accessories"
                products={products.electronics}
                viewAllLink="/products/Electronics"
              />
            )}
            {products.fashion.length > 0 && (
              <ProductSection
                title="👗 Fashion"
                subtitle="Men & Women's Clothing"
                products={products.fashion}
                viewAllLink="/products/Men"
              />
            )}
            {products.grocery.length > 0 && (
              <ProductSection
                title="🥬 Grocery"
                subtitle="Fresh & Packaged Food"
                products={products.grocery}
                viewAllLink="/products/Grocery"
              />
            )}
            {products.books.length > 0 && (
              <ProductSection
                title="📚 Books"
                subtitle="Bestsellers & New Releases"
                products={products.books}
                viewAllLink="/products/Books"
              />
            )}
            {products.recommended.length > 0 && (
              <ProductSection
                title="⭐ Recommended For You"
                subtitle="Based on trending products"
                products={products.recommended}
                viewAllLink="/products"
              />
            )}
          </>
        )}
      </div>
    </div>
  );
};

export default HomePage;
